import { useEffect, useState } from "react"
import "./moviesstyle.css"
function Movies() {
    let [allmovies, changeallmovies] = useState()
    useEffect(() => {
        async function getmovies() {
            let movieslist = []
            for(let i = 1; i <= 5; i++) {
                let fetchmov = await fetch(`https://api.themoviedb.org/3/movie/popular?api_key=438b5d80663af506dbe9658849a35777&language=en-US&page=${i}`)
                let jsonfetchmov = await fetchmov.json()
                let res = jsonfetchmov.results.map((item) => {
                    return <div class="card">
                        <img src={`https://image.tmdb.org/t/p/w500${item.backdrop_path}`}/>
                        <p>{item.original_title}</p>
                        <p>{item.popularity}</p>
                        <p>{item.vote_average}</p>
                        <p>{item.release_date}</p> 
                    </div>
                })//add svg's to each <p>
               changeallmovies(res)
            }
            
        }
        getmovies()
    }, [])
    return<>
        <div>
            {allmovies}
        </div>
    </>
}
export default Movies
